// Generated by OrchestKit Claude Plugin
// Created: 2026-06-07

/**
 * Headroom Store — reversible output compression backing store (#2264).
 *
 * When mcp-output-transform truncates a tool result in the 2K–50K band, it no
 * longer discards the middle. Instead the FULL original is stashed here,
 * content-addressed by hash, and the truncated result carries a pointer telling
 * Claude to `Read` the stash path to recover the skipped chars.
 *
 * Design choices:
 *  - Content-addressed (sha256[:12]): identical outputs dedup to one file, and
 *    the same output across sessions reuses the same stash (skip-write).
 *  - Hash is computed over the POST-redaction text so PII never lands on disk —
 *    callers MUST pass already-redacted content.
 *  - Lives under ~/.claude/state/orchestkit/headroom (NOT the repo tree), so no
 *    .gitignore is needed and the existing session-cleanup TTL sweep can evict it.
 *  - Pure module: no logging, no hook deps. The hook (PR-2) owns wiring + logging.
 *
 * Retrieve side is intentionally absent: Claude already has the `Read` tool, so
 * the pointer path IS the retrieve mechanism. No new tool/MCP server required.
 */

import { existsSync, readdirSync, statSync, unlinkSync } from 'node:fs';
import { createHash } from 'node:crypto';
import { homedir } from 'node:os';
import { join } from 'node:path';
import { atomicWriteSync } from './atomic-write.js';
import { stateRootDir } from './session-state.js';

/** Length of the content-address hash prefix (hex chars). */
export const HASH_LEN = 12;

/** Default TTL for stashed originals — evicted by the session-cleanup sweep. */
export const HEADROOM_DEFAULT_TTL_MS = 7 * 24 * 60 * 60 * 1000; // 7 days

/** Root directory for stashed originals. */
export function getHeadroomDir(home: string = homedir()): string {
  return join(stateRootDir(home), 'headroom');
}

/**
 * Content-address a string: sha256, first HASH_LEN hex chars.
 * Stable across processes and sessions — the basis for dedup.
 */
export function hashContent(text: string): string {
  return createHash('sha256').update(text, 'utf8').digest('hex').slice(0, HASH_LEN);
}

/** Absolute path a given hash stashes to. */
export function stashPath(hash: string, home: string = homedir()): string {
  return join(getHeadroomDir(home), `${hash}.txt`);
}

export interface StashResult {
  /** Content-address of the stashed text. */
  hash: string;
  /** Absolute path the original lives at (what the pointer references). */
  path: string;
  /** False when the file already existed (dedup hit) — no write happened. */
  written: boolean;
}

/**
 * Stash the full (already PII-redacted) original to a content-addressed file.
 *
 * Idempotent: if a file for this hash already exists, it is left untouched and
 * `written` is false (dedup). The write itself is crash-safe via atomicWriteSync.
 *
 * @param redactedText The POST-redaction original. Callers must redact first —
 *   this function does not, and will faithfully persist whatever it is given.
 */
export function stashOriginal(redactedText: string, home: string = homedir()): StashResult {
  const hash = hashContent(redactedText);
  const path = stashPath(hash, home);

  if (existsSync(path)) {
    return { hash, path, written: false };
  }

  atomicWriteSync(path, redactedText);
  return { hash, path, written: true };
}

/**
 * Build the retrieval pointer that replaces the discarded middle.
 *
 * Shape (single line, human + model readable):
 *   [Truncated 12,041→1,800 chars. Full output: Read <path> for the 10,241 chars between.]
 */
export function buildPointer(opts: {
  originalLen: number;
  keptLen: number;
  path: string;
}): string {
  const { originalLen, keptLen, path } = opts;
  const between = Math.max(0, originalLen - keptLen);
  return (
    `[Truncated ${originalLen.toLocaleString()}→${keptLen.toLocaleString()} chars. ` +
    `Full output: Read ${path} for the ${between.toLocaleString()} chars between.]`
  );
}

export interface GcResult {
  /** Files inspected. */
  scanned: number;
  /** Files removed (older than maxAgeMs). */
  removed: number;
}

/**
 * Evict stashed originals older than maxAgeMs (by mtime).
 *
 * Best-effort: a missing dir is a no-op, and per-file errors are swallowed so a
 * single unreadable entry never aborts the sweep. Safe to call from cleanup —
 * a removed stash only degrades a later pointer to today's lossy behavior (the
 * head+tail Claude already has), never a crash.
 *
 * @param now Injected clock for deterministic tests (defaults to Date.now()).
 */
export function gcHeadroom(
  maxAgeMs: number = HEADROOM_DEFAULT_TTL_MS,
  home: string = homedir(),
  now: number = Date.now(),
): GcResult {
  const dir = getHeadroomDir(home);
  const result: GcResult = { scanned: 0, removed: 0 };

  let entries: string[];
  try {
    entries = readdirSync(dir);
  } catch {
    return result; // dir doesn't exist yet — nothing to sweep
  }

  for (const entry of entries) {
    if (!entry.endsWith('.txt')) continue;
    const full = join(dir, entry);
    result.scanned++;
    try {
      const age = now - statSync(full).mtimeMs;
      if (age > maxAgeMs) {
        unlinkSync(full);
        result.removed++;
      }
    } catch {
      // Best-effort: skip entries we can't stat/unlink.
    }
  }

  return result;
}
